always @ (posedge ap_clk) begin
    if (ap_rst_n_inv == 1'b1) begin
        grp_lstm_inference_fu_158_ap_start_reg <= 1'b0;
    end else begin
        if (((ap_start == 1'b1) & (1'b1 == ap_CS_fsm_state1))) begin
            grp_lstm_inference_fu_158_ap_start_reg <= 1'b1;
        end else if ((grp_lstm_inference_fu_158_ap_ready == 1'b1)) begin
            grp_lstm_inference_fu_158_ap_start_reg <= 1'b0;
        end
    end
end

always @ (posedge ap_clk) begin
    if ((1'b1 == ap_CS_fsm_state1)) begin
        bfc_read_reg_195 <= bfc;
        bhh0_read_reg_225 <= bhh0;
        bhh1_read_reg_205 <= bhh1;
        bih0_read_reg_230 <= bih0;
        bih1_read_reg_210 <= bih1;
        input_seq_read_reg_245 <= input_seq;
        pred_out_read_reg_190 <= pred_out;
        wfc_read_reg_200 <= wfc;
        whh0_read_reg_235 <= whh0;
        whh1_read_reg_215 <= whh1;
        wih0_read_reg_240 <= wih0;
        wih1_read_reg_220 <= wih1;
    end
end

always @ (*) begin
    if ((ap_start == 1'b0)) begin
        ap_ST_fsm_state1_blk = 1'b1;
    end else begin
        ap_ST_fsm_state1_blk = 1'b0;
    end
end

always @ (*) begin
